CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE EXTENSION IF NOT EXISTS citext;
DO $$ BEGIN CREATE TYPE audit_result AS ENUM ('success','failure','blocked'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE user_status AS ENUM ('invited','active','locked','disabled','password_reset_required'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
CREATE TABLE IF NOT EXISTS roles (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text UNIQUE NOT NULL, slug text UNIQUE NOT NULL, description text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS permissions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), key text UNIQUE NOT NULL, description text);
CREATE TABLE IF NOT EXISTS role_permissions (role_id uuid REFERENCES roles(id) ON DELETE CASCADE, permission_id uuid REFERENCES permissions(id) ON DELETE CASCADE, PRIMARY KEY(role_id, permission_id));
CREATE TABLE IF NOT EXISTS users (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), role_id uuid NOT NULL REFERENCES roles(id), email citext UNIQUE NOT NULL, full_name text NOT NULL, password_hash text, status user_status NOT NULL DEFAULT 'invited', failed_login_count int NOT NULL DEFAULT 0, locked_until timestamptz, password_changed_at timestamptz, password_expires_at timestamptz, force_password_reset boolean NOT NULL DEFAULT false, last_login_at timestamptz, created_by uuid REFERENCES users(id), created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS sessions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE, refresh_token_hash text NOT NULL UNIQUE, device_fingerprint text NOT NULL, ip_address inet, user_agent text, revoked_at timestamptz, expires_at timestamptz NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), rotated_at timestamptz);
CREATE TABLE IF NOT EXISTS audit_logs (id bigserial PRIMARY KEY, user_id uuid REFERENCES users(id) ON DELETE SET NULL, ip_address inet, device text, action text NOT NULL, result audit_result NOT NULL, metadata jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS password_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE, password_hash text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS password_reset_tokens (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE, token_hash text NOT NULL UNIQUE, expires_at timestamptz NOT NULL, used_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS email_verifications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE, token_hash text NOT NULL UNIQUE, purpose text NOT NULL, expires_at timestamptz NOT NULL, used_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS device_registrations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE, fingerprint_hash text NOT NULL, label text, first_seen_at timestamptz NOT NULL DEFAULT now(), last_seen_at timestamptz NOT NULL DEFAULT now(), trusted_at timestamptz, UNIQUE(user_id, fingerprint_hash));
CREATE INDEX IF NOT EXISTS idx_sessions_user_active ON sessions(user_id) WHERE revoked_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_audit_user_created ON audit_logs(user_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_password_reset_active ON password_reset_tokens(user_id, expires_at) WHERE used_at IS NULL;
INSERT INTO roles(name, slug, description) VALUES ('Super Admin','super-admin','System owner with unrestricted access'),('Executive Management','executive-management','Executive reporting and governance'),('HR Manager','hr-manager','Human resources administration'),('Finance Manager','finance-manager','Financial operations'),('Operations Manager','operations-manager','Operational workflow management'),('Legal Manager','legal-manager','Legal services management'),('Standard Staff','standard-staff','General staff access') ON CONFLICT DO NOTHING;
INSERT INTO permissions(key, description) VALUES ('users.manage','Create and manage staff'),('roles.manage','Change roles'),('audit.read','View audit logs'),('sessions.revoke','Revoke user sessions'),('dashboard.read','Read assigned dashboard') ON CONFLICT DO NOTHING;
INSERT INTO role_permissions(role_id, permission_id) SELECT r.id,p.id FROM roles r CROSS JOIN permissions p WHERE r.slug='super-admin' ON CONFLICT DO NOTHING;
